// Cache للأدوات المحمّلة
const toolCache = new Map<string, MCPTool>();

/** قائمة كل الأدوات (metadata فقط — بدون loading) */
export function listTools() {
  return TOOL_META.map(t => ({
    name: t.name,
    description: t.description,
    parameters: t.parameters,
  })) as MCPTool[];
}

/** قائمة كل أسماء الأدوات المتاحة (سريع - metadata فقط) */
export function listToolNames(): string[] {
  return TOOL_META.map(t => t.name);
}

/** التحقق من وجود أداة بالاسم (static + dynamic) */
export function hasTool(name: string): boolean {
  // static check
  if (TOOL_LOADERS[name] !== undefined || TOOL_META.some(t => t.name === name)) return true;
  // dynamic check (sync — مش بنعمل async query هنا)
  return false;
}

/** التحقق من وجود أداة بالاسم (async — يشمل dynamic tools) */
export async function hasToolAsync(name: string): Promise<boolean> {
  if (hasTool(name)) return true;
  try {
    const { getDynamicTools } = await import("./dynamic-registry");
    const dynamic = await getDynamicTools();
    return dynamic.some(t => t.name === name);
  } catch {
    return false;
  }
}

/** الحصول على metadata أداة واحدة (بدون loading) */
export function getToolMeta(name: string): { name: string; description: string; parameters: any } | undefined {
  return TOOL_META.find(t => t.name === name);
}

/** الحصول على tool بالاسم (lazy load — static + dynamic) */
export async function getTool(name: string): Promise<MCPTool | undefined> {
  // static first
  if (toolCache.has(name)) return toolCache.get(name);
  const loader = TOOL_LOADERS[name];
  if (loader) {
    const tool = await loader();
    toolCache.set(name, tool);
    return tool;
  }
  // dynamic (from DB)
  try {
    const { getDynamicTools } = await import("./dynamic-registry");
    const dynamic = await getDynamicTools();
    return dynamic.find(t => t.name === name);
  } catch {
    return undefined;
  }
}

/** تنفيذ tool بالاسم (static + dynamic) */
export async function executeTool(name: string, params: Record<string, unknown>): Promise<MCPToolResult> {
  const tool = await getTool(name);
  if (!tool) return { success: false, error: `Tool "${name}" غير موجودة` };
  try {
    return await tool.execute(params);
  } catch (e: any) {
    return { success: false, error: e.message };
  }
}

/** تحويل كل الأدوات لصيغة GLM function calling (static + dynamic) */
export async function toGLMTools() {
  const staticTools = TOOL_META.map(t => ({
    type: "function" as const,
    function: { name: t.name, description: t.description, parameters: t.parameters },
  }));
  try {
    const { getDynamicTools } = await import("./dynamic-registry");
    const dynamic = await getDynamicTools();
    const dynamicTools = dynamic.map(t => ({
      type: "function" as const,
      function: { name: t.name, description: t.description, parameters: t.parameters },
    }));
    return [...staticTools, ...dynamicTools];
  } catch {
    return staticTools;
  }
}
